on_write:
let res = #{ action: "Allow" };
if !payload.contains("links") {
    res.action = "Reject";
    res.reason = "Network nodes must have a links array";
}
res

on_read:
let res = #{ payload: payload };
// Basic check if network links contain the target node
if payload.links.contains(query_key) {
    res.match_found = true;
} else {
    res.match_found = false;
}
res
